mapper.select:
select r.id, s.name as userName, b.title as bookTitle, r.borrow_date as borrowDate, r.due_date as dueDate, r.status
from borrow_record r
left join student s on r.user_id = s.id
left join book b on r.book_id = b.id

    and r.user_id = #{userId}
    and r.book_id = #{bookId}
    and r.status = #{status}

order by r.id desc

SELECT
    COUNT(*) as totalBorrows,
    SUM(CASE WHEN r.status = '借阅中' THEN 1 ELSE 0 END) as currentBorrows,
    SUM(CASE WHEN r.status = '逾期' THEN 1 ELSE 0 END) as overdueBorrows,
    AVG(DATEDIFF(COALESCE(r.return_date, CURDATE()), r.borrow_date)) as averageBorrowDays
FROM borrow_record r
WHERE 1=1
AND r.user_id = #{userId}
AND r.borrow_date >= #{startDate}
AND r.borrow_date <= #{endDate}
